import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base premiums
  it.todo("should return 5G premium for empty item list (processing fee only)");
  it.todo("should return 115G premium for a single plain sword (100 base + 10% first insurance + 5 fee)");
  it.todo("should return 71G premium for a single plain amulet (60 base + 6 first insurance + 5 fee)");
  it.todo("should return 93G premium for a single plain staff (80 base + 8 first insurance + 5 fee)");
  it.todo("should return 49G premium for a single plain potion (40 base + 4 first insurance + 5 fee)");

  // Quote: components
  it.todo("should return 33G premium for a single rune (25 base + 2.5 first insurance → ceil 28 + 5 fee)");
  it.todo("should return 61G premium for 2 runes (50 base + 5 first insurance + 5 fee + 1 rounding)");
  it.todo("should return 71G premium for 3 alike runes (60 block base + 6 first insurance + 5 fee)");
  it.todo("should return 115G premium for 4 runes (100 base + 10 first insurance + 5 fee)");
  it.todo("should return 83G premium for 2 runes + 1 moonstone (75 base + 7.5 first insurance → ceil 83 + 5 fee)");
  it.todo("should return 137G premium for 3 runes + 3 moonstones (120 block base + 12 first insurance + 5 fee)");

  // Quote: cursed surcharge (item-level)
  it.todo("should return 165G premium for a cursed sword (100 base + 50 curse + 10% first insurance on 100 + 5 fee)");

  // Quote: high enchantment surcharge (item-level)
  it.todo("should add 30% high-enchantment surcharge for enchantment level 5");
  it.todo("should not add high-enchantment surcharge for enchantment level 4");

  // Quote: cursed + high enchantment combined
  it.todo("should apply both cursed and high-enchantment surcharges on the same item");

  // Quote: multi-item policy with item-specific modifiers
  it.todo("should apply cursed surcharge only to the cursed item in a multi-item policy");

  // Quote: loyalty discount (policy-level)
  it.todo("should apply 20% loyalty discount for customer with 2+ years");
  it.todo("should not apply loyalty discount for customer with less than 2 years");

  // Quote: follow-up contract discount (policy-level)
  it.todo("should apply 15% follow-up discount on second quote");

  // Quote: integration — newcomer with cursed sword
  it.todo("should return 165G for newcomer with cursed sword (integration example 1)");

  // Quote: integration — long-standing customer second contract
  it.todo("should return 160G for long-standing customer second contract with cursed+enchanted sword (integration example 2)");

  // Claim: basic payout with deductible
  it.todo("should return payout of 400G for regular sword with 500G damage (500 - 100 deductible)");

  // Claim: deductible per item
  it.todo("should apply 100G deductible per damaged item in a single event");

  // Claim: high enchantment reimbursement
  it.todo("should reimburse at 50% for item with enchantment >= 8 then apply deductible");

  // Claim: dragon material full reimbursement
  it.todo("should fully reimburse dragon material item then apply deductible");

  // Claim: dragon material + high enchantment
  it.todo("should apply 50% when both dragon material and enchantment >= 8");
  it.todo("should fully reimburse dragon material with enchantment < 8");

  // Claim: component damage
  it.todo("should reimburse component damage with deductible, no special clauses");

  // Claim: cap = 2x insurance sum
  it.todo("should cap total payout at twice the insurance sum");

  // Claim: cap exhaustion across multiple claims
  it.todo("should track remaining cap across successive claims on the same policy");

  // Claim: error — damage to item not in policy
  it.todo("should throw error when damage references item not in policy");

  // Claim: error — more damages than insured items
  it.todo("should throw error when damages exceed insured item count for a type");

  // Claim: error — negative damage
  it.todo("should throw error for negative damage amount");

  // Quote: error — unknown item type
  it.todo("should throw error for unknown item type in quote");

  // Rounding
  it.todo("should round premium up in MHPCO favor (ceil)");
  it.todo("should round payout down in MHPCO favor (floor)");
});

