interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Array<{ op: string; [key: string]: any }>;
}

interface ScenarioOutput {
  results: Array<{ premium?: number; payout?: number; remainingCap?: number }>;
}

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const PROCESSING_FEE = 5;

export function processScenario(scenario: Scenario): ScenarioOutput {
  const results = scenario.steps.map((step) => {
    const items = step.items || [];
    let basePremium = 0;
    const componentCounts: Record<string, number> = {};
    for (const item of items) {
      if (item.type in BASE_PREMIUMS) {
        basePremium += BASE_PREMIUMS[item.type];
      } else {
        componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
      }
    }
    for (const count of Object.values(componentCounts)) {
      if (count === COMPONENT_BLOCK_SIZE) {
        basePremium += COMPONENT_BLOCK_PREMIUM;
      } else {
        basePremium += count * COMPONENT_PREMIUM;
      }
    }
    const premium =
      Math.ceil(basePremium + basePremium * FIRST_INSURANCE_SURCHARGE) +
      PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

